SELECT CHAM.SEMESTRE FROM CALC_HORA_AULA_MEDIA CHAM WHERE CHAM.ANO = 2021 AND CHAM.AREA_INGRESSO = 'ENGENHARIA CIVIL' AND CHAM.SIGLA_CAMPUS = 'ANA' AND CHAM.SIAPE IN (SELECT S.PK_SIAPE FROM SERVIDOR S WHERE S.CONTRATO = 'EFETIVOS') GROUP BY CHAM.ANO, CHAM.SEMESTRE HAVING COUNT(DISTINCT CHAM.SIAPE) = 9 ORDER BY CHAM.SEMESTRE LIMIT 1